unstable_cache(
        async () => {
            const setting = await prisma.setting.findUnique({
                where: {
                    shopId_key: {
                        shopId,
                        key: "gemini_api_key"
                    }
                }
            });
            return setting?.value || process.env.GEMINI_API_KEY || "";
        },
        [`gemini-api-key-${shopId}`],
        { tags: ["settings", `settings-${shopId}`], revalidate: 900 }
    )
